
.panel-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 12px;
}

.panel-card {
  padding: 14px;
  background: rgba(15, 23, 42, 0.6);
  border: 1px solid rgba(148, 163, 184, 0.15);
  border-radius: 14px;
}

.highlight-card {
  background: linear-gradient(180deg, rgba(245, 158, 11, 0.08), transparent 60%), rgba(15, 23, 42, 0.64);
}

.full-span {
  grid-column: 1 / -1;
}

.section-head {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 10px;
  margin-bottom: 12px;
}

.section-title {
  font-size: 0.9rem;
  color: var(--c-text);
  font-weight: 700;
}

.pill {
  display: inline-flex;
  align-items: center;
  border-radius: 999px;
  padding: 3px 10px;
  font-size: 0.72rem;
}

.pill.neutral {
  background: rgba(234, 179, 8, 0.14);
  color: #fde68a;
}

.pill.active {
  background: rgba(56, 189, 248, 0.14);
  color: #bae6fd;
}

.pill.done {
  background: rgba(34, 197, 94, 0.14);
  color: #bbf7d0;
}

.cargo-title-row {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  gap: 10px;
  margin-bottom: 12px;
}

.cargo-name {
  font-size: 1.08rem;
  color: var(--c-text);
  font-weight: 700;
}

.cargo-sub {
  margin-top: 4px;
  color: var(--c-muted);
  font-size: 0.8rem;
}

.reward-box {
  padding: 8px 10px;
  border-radius: 10px;
  background: rgba(34, 197, 94, 0.1);
  color: #dcfce7;
  font-weight: 700;
  white-space: nowrap;
}

.route-card {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
  padding: 12px;
  border-radius: 12px;
  background: rgba(30, 41, 59, 0.88);
  margin-bottom: 12px;
  color: var(--c-text);
  font-weight: 700;
  text-align: center;
}

.route-chain {
  flex-wrap: wrap;
}

.route-node {
  padding: 4px 10px;
  border-radius: 999px;
  border: 1px solid rgba(148, 163, 184, 0.18);
  font-size: 0.84rem;
}

.route-node-active {
  background: rgba(56, 189, 248, 0.14);
  color: #bae6fd;
}

.route-node-idle {
  background: rgba(15, 23, 42, 0.48);
  color: var(--c-muted);
}

.arrow {
  color: var(--c-accent-soft);
}

.progress-head,
.info-item {
  display: flex;
  justify-content: space-between;
  gap: 12px;
}

.progress-head {
  margin-bottom: 8px;
  color: var(--c-muted);
  font-size: 0.78rem;
}

.progress-track {
  width: 100%;
  height: 10px;
  border-radius: 999px;
  overflow: hidden;
  background: rgba(51, 65, 85, 0.86);
}

.progress-fill {
  height: 100%;
  border-radius: inherit;
  background: linear-gradient(90deg, #38bdf8, #a78bfa);
}

.info-list {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.label {
  color: var(--c-muted);
  font-size: 0.8rem;
}

.value {
  color: var(--c-text);
  font-size: 0.84rem;
  text-align: right;
}

.tag-list {
  display: flex;
  flex-wrap: wrap;
  justify-content: flex-end;
  gap: 6px;
}

.tag {
  padding: 2px 8px;
  border-radius: 999px;
  font-size: 0.72rem;
  background: rgba(245, 158, 11, 0.12);
  color: #fde68a;
}

.monitor-grid {
  display: grid;
  grid-template-columns: repeat(3, minmax(0, 1fr));
  gap: 10px;
}

.monitor-item {
  display: flex;
  flex-direction: column;
  gap: 5px;
  padding: 12px;
  background: rgba(30, 41, 59, 0.88);
  border-radius: 12px;
}

.monitor-key {
  color: var(--c-muted);
  font-size: 0.76rem;
}

.monitor-value {
  color: var(--c-text);
  font-size: 0.95rem;
  font-weight: 700;
  word-break: break-word;
}

.empty-panel,
.empty-text {
  color: var(--c-muted);
  font-size: 0.8rem;
}

@media (max-width: 720px) {
  .panel-grid,
  .monitor-grid {
    grid-template-columns: 1fr;
  }

  .cargo-title-row,
  .info-item {
    flex-direction: column;
  }

  .tag-list {
    justify-content: flex-start;
  }

  .value {
    text-align: left;
  }
}
