
.dashboard-shell {
  width: 100%;
  max-width: 860px;
  margin: 0 auto;
  display: flex;
  flex-direction: column;
  background:
    linear-gradient(180deg, rgba(245, 158, 11, 0.08), transparent 42%),
    linear-gradient(180deg, var(--c-panel), var(--c-bg));
  border: 1px solid rgba(245, 158, 11, 0.28);
  border-radius: 18px;
  overflow: hidden;
  box-shadow: var(--shadow-panel);
}

.content-area {
  padding: 14px;
  min-height: 180px;
}
