
.vehicle-layout {
  display: grid;
  grid-template-columns: 1fr;
  gap: 12px;
}

.panel-card {
  padding: 14px;
  background: rgba(15, 23, 42, 0.6);
  border: 1px solid rgba(148, 163, 184, 0.15);
  border-radius: 14px;
}

.overview-card {
  background:
    linear-gradient(180deg, rgba(56, 189, 248, 0.08), transparent 60%),
    rgba(15, 23, 42, 0.64);
}

.section-head {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 10px;
  margin-bottom: 12px;
}

.section-title {
  font-size: 0.9rem;
  color: var(--c-text);
  font-weight: 700;
}

.truck-name {
  color: var(--c-text);
  font-size: 1.08rem;
  font-weight: 700;
}

.truck-meta {
  margin-top: 8px;
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
  color: var(--c-muted);
  font-size: 0.8rem;
}

.truck-meta span {
  padding: 3px 8px;
  border-radius: 999px;
  background: rgba(30, 41, 59, 0.88);
}

.summary-pill,
.status-pill {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 3px 10px;
  border-radius: 999px;
  font-size: 0.72rem;
}

.excellent {
  background: rgba(56, 189, 248, 0.14);
  color: #bae6fd;
}

.good {
  background: rgba(34, 197, 94, 0.14);
  color: #bbf7d0;
}

.warning {
  background: rgba(249, 115, 22, 0.14);
  color: #fdba74;
}

.danger {
  background: rgba(239, 68, 68, 0.14);
  color: #fecaca;
}

.component-list {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 10px;
}

.component-card {
  display: grid;
  grid-template-columns: minmax(0, 1fr) auto;
  gap: 8px 10px;
  align-items: center;
  padding: 10px 12px;
  border-radius: 12px;
  background: rgba(30, 41, 59, 0.88);
  min-width: 0;
}

.component-info {
  min-width: 0;
}

.component-title-line {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 8px;
}

.component-name {
  color: var(--c-text);
  font-weight: 700;
  font-size: 0.98rem;
}

.component-meta {
  margin-top: 2px;
  color: var(--c-muted);
  font-size: 0.74rem;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.condition-meter {
  display: flex;
  align-items: center;
  gap: 6px;
  justify-content: flex-end;
  align-self: center;
}

.dot {
  width: 10px;
  height: 10px;
  border-radius: 50%;
  background: rgba(71, 85, 105, 0.7);
  border: 1px solid rgba(148, 163, 184, 0.18);
}

.dot.active.excellent {
  background: #38bdf8;
}

.dot.active.good {
  background: #22c55e;
}

.dot.active.warning {
  background: #f97316;
}

.dot.active.danger {
  background: #ef4444;
}

@media (max-width: 720px) {
  .component-list {
    grid-template-columns: 1fr;
  }
}
