
.overview-layout {
  display: grid;
  grid-template-columns: 1fr;
  gap: 12px;
}

.panel-card {
  padding: 14px;
  background: rgba(15, 23, 42, 0.6);
  border: 1px solid rgba(148, 163, 184, 0.15);
  border-radius: 14px;
}

.info-card {
  background: linear-gradient(180deg, rgba(245, 158, 11, 0.08), transparent 60%), rgba(15, 23, 42, 0.64);
}

.section-head {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 10px;
  margin-bottom: 12px;
}

.section-title {
  font-size: 0.9rem;
  color: var(--c-text);
  font-weight: 700;
}

.money-pill {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  border-radius: 999px;
  padding: 4px 10px;
  background: rgba(34, 197, 94, 0.14);
  color: #bbf7d0;
  font-size: 0.8rem;
  font-weight: 700;
}

.fatigue-pill {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 4px 12px;
  border-radius: 999px;
  font-size: 0.8rem;
  font-weight: 700;
  border: 1px solid rgba(148, 163, 184, 0.2);
}

.meta-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 10px;
}

.meta-item {
  display: flex;
  flex-direction: column;
  gap: 4px;
  padding: 12px;
  border-radius: 12px;
  background: rgba(30, 41, 59, 0.88);
}

.meta-item-warn {
  box-shadow: inset 0 0 0 1px rgba(249, 115, 22, 0.28);
  background: rgba(51, 33, 19, 0.76);
}

.radio-head {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 8px;
}

.meta-label {
  font-size: 0.72rem;
  color: var(--c-muted);
}

.meta-value {
  font-size: 0.95rem;
  color: var(--c-text);
  font-weight: 700;
}

.meta-value.warn-text,
.meta-sub.warn-text {
  color: #fdba74;
}

.meta-sub {
  font-size: 0.78rem;
  color: var(--c-muted);
}

.quick-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 10px;
}

.quick-item {
  display: flex;
  flex-direction: column;
  gap: 8px;
  padding: 12px;
  border-radius: 12px;
  background: rgba(30, 41, 59, 0.88);
}

.quick-head {
  display: flex;
  justify-content: space-between;
  gap: 8px;
  color: var(--c-muted);
  font-size: 0.78rem;
}

.quick-emphasis {
  color: #bbf7d0;
  font-weight: 700;
}

.quick-emphasis.warn {
  color: #fecaca;
}

.quick-line {
  color: var(--c-text);
  font-size: 1.02rem;
  font-weight: 700;
}

.quick-line.overspeed {
  color: #fca5a5;
}

.quick-hint {
  color: var(--c-muted);
  font-size: 0.74rem;
}

.progress-track {
  width: 100%;
  height: 9px;
  border-radius: 999px;
  overflow: hidden;
  background: rgba(51, 65, 85, 0.86);
}

.progress-fill {
  height: 100%;
  border-radius: inherit;
  transition: width 0.25s ease;
}

.progress-fill.fuel {
  background: linear-gradient(90deg, #22c55e, #84cc16);
}

.progress-fill.fuel.warn {
  background: linear-gradient(90deg, #f97316, #ef4444);
}

.progress-fill.trip {
  background: linear-gradient(90deg, #38bdf8, #a78bfa);
}

.pill {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 2px 8px;
  border-radius: 999px;
  font-size: 0.7rem;
  border: 1px solid rgba(148, 163, 184, 0.2);
  color: var(--c-text);
}

.pill.safe,
.pill.success {
  background: rgba(34, 197, 94, 0.14);
  color: #bbf7d0;
}

.pill.caution,
.pill.neutral {
  background: rgba(234, 179, 8, 0.14);
  color: #fde68a;
}

.pill.warn {
  background: rgba(249, 115, 22, 0.14);
  color: #fdba74;
}

.pill.danger {
  background: rgba(239, 68, 68, 0.14);
  color: #fecaca;
}

@media (max-width: 720px) {
  .quick-grid {
    grid-template-columns: 1fr;
  }
}

@media (max-width: 980px) {
  .meta-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }
}

@media (max-width: 620px) {
  .meta-grid {
    grid-template-columns: 1fr;
  }
}
