
.archive-layout {
  display: grid;
  grid-template-columns: 1fr;
  gap: 12px;
}

.panel-card {
  padding: 14px;
  background: rgba(15, 23, 42, 0.6);
  border: 1px solid rgba(148, 163, 184, 0.15);
  border-radius: 14px;
}

.hero-card {
  background: linear-gradient(180deg, rgba(56, 189, 248, 0.08), transparent 60%), rgba(15, 23, 42, 0.64);
}

.section-head {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 10px;
  margin-bottom: 12px;
}

.section-title {
  font-size: 0.9rem;
  color: var(--c-text);
  font-weight: 700;
}

.meta-label {
  font-size: 0.72rem;
  color: var(--c-muted);
}

.meta-sub {
  font-size: 0.78rem;
  color: var(--c-muted);
}

.archive-grid {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 10px;
}

.archive-item {
  display: flex;
  flex-direction: column;
  gap: 4px;
  padding: 12px;
  border-radius: 12px;
  background: rgba(30, 41, 59, 0.88);
}

.archive-value {
  font-size: 1.02rem;
  color: var(--c-text);
  font-weight: 700;
}

@media (max-width: 720px) {
  .archive-grid {
    grid-template-columns: 1fr;
  }
}
