
.topbar {
  display: flex;
  flex-direction: column;
  gap: 10px;
  padding: 12px 14px;
  background:
    radial-gradient(circle at top right, rgba(245, 158, 11, 0.18), transparent 45%),
    linear-gradient(180deg, rgba(15, 23, 42, 0.94), rgba(15, 23, 42, 0.88));
  border-bottom: 1px solid rgba(148, 163, 184, 0.15);
}

.topbar-head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
}

.brand {
  display: flex;
  align-items: center;
  gap: 8px;
  min-width: 0;
}

.icon {
  font-size: 1.3rem;
}

.brand-text {
  min-width: 0;
}

.title {
  color: var(--c-text);
  font-size: 1.02rem;
  font-weight: 700;
  white-space: nowrap;
}

.subtitle {
  color: var(--c-muted);
  font-size: 0.75rem;
  margin-top: 2px;
  white-space: nowrap;
  text-overflow: ellipsis;
  overflow: hidden;
}

.tabs {
  display: flex;
  align-items: stretch;
  justify-content: flex-start;
  background: rgba(15, 23, 42, 0.56);
  border: 1px solid rgba(148, 163, 184, 0.18);
  border-radius: 10px;
  overflow-x: auto;
  overflow-y: hidden;
  width: fit-content;
  max-width: 100%;
  margin: 0 auto;
  scrollbar-width: none;
}

.tabs::-webkit-scrollbar {
  display: none;
}

.weather {
  justify-self: end;
  display: flex;
  flex-direction: column;
  align-items: flex-end;
  gap: 2px;
  padding: 7px 10px;
  border-radius: 999px;
  border: 1px solid rgba(148, 163, 184, 0.2);
  background: rgba(15, 23, 42, 0.58);
  white-space: nowrap;
}

.weather-line {
  display: flex;
  align-items: center;
  gap: 8px;
}

.weather-meta {
  color: var(--c-muted);
  font-size: 0.78rem;
}

.weather-main {
  color: #fde68a;
  font-size: 0.82rem;
  font-weight: 700;
}

.weather-temp {
  color: var(--c-muted);
  font-size: 0.78rem;
}

.tab-button {
  appearance: none;
  border: none;
  background: transparent;
  color: var(--c-muted);
  padding: 9px 20px;
  min-width: 108px;
  flex: 0 0 auto;
  cursor: pointer;
  font-size: 0.84rem;
  letter-spacing: 0.04em;
  transition: 0.2s ease;
  border-right: 1px solid rgba(148, 163, 184, 0.15);
  white-space: nowrap;
  text-align: center;
}

.tab-button:last-child {
  border-right: none;
}

.tab-button:hover {
  color: var(--c-text);
  background: rgba(245, 158, 11, 0.08);
}

.tab-button.active {
  color: var(--c-text);
  background: linear-gradient(180deg, rgba(245, 158, 11, 0.28), rgba(245, 158, 11, 0.12)), rgba(15, 23, 42, 0.72);
  box-shadow: inset 0 -1px 0 var(--c-accent);
}

@media (max-width: 860px) {
  .topbar-head {
    align-items: flex-start;
  }

  .weather {
    justify-self: end;
    align-items: flex-end;
    padding: 6px 9px;
    max-width: 100%;
  }

  .weather-line-main {
    justify-content: flex-end;
  }

  .weather-line-meta {
    justify-content: flex-end;
  }

  .weather-main {
    font-size: 0.78rem;
  }

  .weather-temp,
  .weather-meta {
    font-size: 0.72rem;
  }

  .tab-button {
    text-align: center;
    padding: 10px 14px;
    min-width: 92px;
    font-size: 0.8rem;
  }
}

@media (max-width: 560px) {
  .topbar-head {
    flex-direction: column;
    gap: 8px;
  }

  .weather {
    align-self: flex-end;
  }
}
